public class ETGITMCreatorCreateShipmentTaskBaseOut extends RunBaseBatch implements BatchRetryable
{
    private ITMTable itmTable;
    private ITMContainerId shipContainerId;
    private ITMContainers itmContainers;
    private ITMTmpCreatorLine itmTmpCreatorLine;
    private ETGITMAddBucketContainerFormHandlerOut formHandler;
    private boolean addToExistingContainers;
    private List recordList = new List(Types::Record);
    private boolean localCanGoBatch;

    private container tmpCreatorLineContainer;

    private const int CurrentVersion = 1;
    #localmacro.CurrentList
        itmTable,
        itmContainers,
        addToExistingContainers
    #endmacro

}

