public static ClassDescription description()
{
    return "@InboundTransportationManagement:ITMAddToConatinerJob";
}

public Object dialog()
{
    DialogRunBase dialog = super();
    if (!addToExistingContainers)
    {
        dialog = this.dialogInternal(Dialog::newFormnameRunbase(formstr(ETGITMContainersCreateFromBucketOut), this));
    }
    else
    {
        formHandler.refreshCallingDatasource();
    }
    return dialog;
}

static ETGITMCreatorCreateShipmentTaskBaseOut newITMCreatorCreateShipmentTaskBaseFromArgs(Args args)
{
    ETGITMCreatorCreateShipmentTaskBaseOut createShipment = ETGITMCreatorCreateShipmentTaskBaseOut::construct();
    ETGITMAddBucketContainerFormHandlerOut handler = args.caller();

    createShipment.parmITMTable(handler.parmITMTable());
    createShipment.parmITMContainers(handler.parmITMContainers());
    createShipment.parmITMTmpCreatorLine(handler.parmTmpCreatorLine());
    createShipment.parmAddToExistingContainers(handler.parmAddToExistingContainers());
    createShipment.parmITMAddBucketContainerFormHandler(handler);
    createShipment.checkCanGoBatch();

    return createShipment;
}

public boolean allowSaveLast()
{
    return false;
}

public boolean canGoBatch()
{
    return true;
}

public boolean runsImpersonated()
{
    return true;
}

protected boolean canRunInNewSession()
{
    return true;
}

static void main(Args args)
{
    ETGITMCreatorCreateShipmentTaskBaseOut createShipment = ETGITMCreatorCreateShipmentTaskBaseOut::newITMCreatorCreateShipmentTaskBaseFromArgs(args);
    ETGITMAddBucketContainerFormHandlerOut handler = args.caller();
    if (createShipment.prompt())
    {
        createShipment.runOperation();
        handler.parmOperationCompleted(true);
    }
}

public void getLast()
{
    super();
    if (!localCanGoBatch && this.batchInfo())
    {
        this.batchInfo().parmBatchExecute(NoYes::No);
    }
}

static ETGITMCreatorCreateShipmentTaskBaseOut construct()
{
    return new ETGITMCreatorCreateShipmentTaskBaseOut();
}

public void checkCanGoBatch()
{
    itmTmpCreatorLine itmTmpCreatorLineLocal;
    itmTmpCreatorLineLocal.setTmpData(itmTmpCreatorLine);

    select firstonly itmTmpCreatorLineLocal
        where itmTmpCreatorLineLocal.TransferQty < itmTmpCreatorLineLocal.PurchQty
            && itmTmpCreatorLineLocal.Selected == NoYes::Yes
            && itmTmpCreatorLineLocal.AddedToBucket == NoYes::Yes
            && itmTmpCreatorLineLocal.TransferQty > 0;

    localCanGoBatch = !itmTmpCreatorLineLocal.RecId;
    if (!itmTmpCreatorLineLocal.RecId)
    {
        this.batchInfo().parmBatchExecute(NoYes::No);
    }
}

public container pack()
{
    boolean runInBatch = this.isInBatch();
    if (recordList.empty())
    {
        while select itmTmpCreatorLine
        {
            recordList.addEnd(itmTmpCreatorLine);
        }
    }
    return [CurrentVersion, #CurrentList, recordList.pack()];
}

public boolean unpack(container _packedClass)
{
    Version version = RunBase::getVersion(_packedClass);
    boolean ret;

    switch (version)
    {
        case CurrentVersion:
            [version, #CurrentList, tmpCreatorLineContainer] = _packedClass;
            ListEnumerator le = List::create(tmpCreatorLineContainer).getEnumerator();
            select firstonly itmTmpCreatorLine;
            if (!itmTmpCreatorLine)
            {
                while (le.movenext())
                {
                    itmTmpCreatorLine.clear();
                    buf2Buf(le.current(), itmTmpCreatorLine);
                    itmTmpCreatorLine.insert();
                }
            }
            ret = true;
            break;

        default:
            ret = false;
    }

    return ret;
}

[Hookable(false)]
final boolean isRetryable()
{
    return true;
}

public void addContainers(boolean _addToExistContainer = false)
{
    boolean ret = ETGITMCreatorCreateShipmentOut::createShipmentFromShipEditor(
                itmTmpCreatorLine,
                itmTable,
                itmContainers,
                _addToExistContainer);
    if (!ret)
    {
        throw error("@SYS18447");
    }
}

public void run()
{
    #OCCRetryCount

    try
    {
        ttsbegin;

        this.validateTmpCreatorLine();

        this.addContainers(addToExistingContainers);

        ttscommit;
    }
    catch (Exception::Deadlock)
    {
        retry;
    }
    catch (Exception::UpdateConflict)
    {
        if (appl.ttsLevel() == 0)
        {
            if (xSession::currentRetryCount() >= #RetryNum)
            {
                throw Exception::UpdateConflictNotRecovered;
            }
            else
            {
                retry;
            }
        }
        else
        {
            throw Exception::UpdateConflict;
        }
    }
}

public void validateTmpCreatorLine()
{
    ITMLine ITMLine;

    ttsbegin;

    while select forupdate itmTmpCreatorLine
        where itmTmpCreatorLine.AddedToBucket && itmTmpCreatorLine.Selected
        exists join ITMLine
            where ITMLine.InventTransId == itmTmpCreatorLine.InventTransId
            && ITMLine.ShipDataArea == itmTmpCreatorLine.ShipDataArea
    {
        warning(strFmt("@InboundTransportationManagement:ItemAlreadyAddedToShipment", itmTmpCreatorLine.ItemId));

        itmTmpCreatorLine.delete();
    }

    ttscommit;
}

protected void dialogPost(Object dialog)
{
    super(dialog);

    DialogRunbase dialogRunbase = dialog as dialogRunbase;
    if (dialogRunbase != null)
    {
      //  dialogRunbase.disableRecurrenceButton();
      //todo vinay  dialogRunbase.disableRecurrenceButton();
    }
}

public void dialogPostRun(DialogRunbase dialog)
{
    super(dialog);

    if (!this.localCanGoBatch)
    {
        List controlList = dialog.formRun().controlList();
        ListEnumerator le = controlList.getEnumerator();
        while (le.moveNext())
        {
            Object control = le.current();
            if (control && classIdGet(control) == classNum(FormCheckBoxControl))
            {
                FormCheckBoxControl batchProcessingControl = control;
                if (batchProcessingControl.label()  == "@SYS2312")
                {
                    batchProcessingControl.value(NoYes::No);
                    batchProcessingControl.registerOverrideMethod(methodStr(FormCheckBoxControl, validate), methodStr(ITMCreatorCreateShipmentTaskBase, validateBatchProcessing), this);
                    break;
                }
            }
        }
    }
}

public boolean validateBatchProcessing(FormControl _formControl)
{
    return checkFailed("@InboundTransportationManagement:ITMPartialAddNoBatchMessage");
}
